### Blueprint 1: Robust Hybrid Loop & State Persistence Engine

Save this file as `src/runner/state-manager.js`. This module uses a complete JSON flat-file schema to write state data atomically using temporary files, which prevents data corruption.

```javascript
'use strict';

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

class StateManager {
  /**
   * Initializes a persistent state manager for the current run session.
   * @param {string} logDirectory Target folder location to store state JSON files
   */
  constructor(logDirectory) {
    this.logDirectory = logDirectory;
    if (!fs.existsSync(logDirectory)) {
      fs.mkdirSync(logDirectory, { recursive: true });
    }
  }

  /**
   * Generates a structural JSON file name based on a session UUID or timestamp.
   * @returns {string} Fully qualified path to the state file
   */
  createSessionPath() {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const randomId = crypto.randomBytes(4).toString('hex');
    return path.join(this.logDirectory, `session-${timestamp}-${randomId}.state.json`);
  }

  /**
   * Atomically writes execution state to a file to prevent data corruption.
   * @param {string} statePath The target state file path
   * @param {object} rawMessages The list of clean Anthropic messages
   * @param {object} metadata Context configurations and runtime arguments
   * @param {object} internalState Internal counters and logging buffers
   */
  save(statePath, rawMessages, metadata, internalState) {
    const payload = {
      schemaVersion: "1.1.0",
      sessionUuid: metadata.runId || crypto.randomUUID(),
      runnerState: {
        cwd: metadata.cwd,
        model: metadata.model,
        maxSteps: metadata.maxSteps,
        currentStep: metadata.step,
        consecutiveToolFailures: internalState.consecutiveToolFailures || 0,
        runningUsage: internalState.totalUsage || {
          input_tokens: 0,
          output_tokens: 0,
          cache_read_input_tokens: 0,
          cache_creation_input_tokens: 0
        },
        undoLog: internalState.undoLog || [],
        clientFlags: {
          allowShell: !!metadata.allowShell,
          acceptEdits: !!metadata.acceptEdits,
          dontAsk: !!metadata.dontAsk,
          noNetwork: !!metadata.noNetwork
        }
      },
      rawMessages: this.sanitizeMessagesForAnthropic(rawMessages)
    };

    const tempPath = `${statePath}.${crypto.randomBytes(4).toString('hex')}.tmp`;
    try {
      // Write to a temporary file, then rename it to ensure atomicity.
      fs.writeFileSync(tempPath, JSON.stringify(payload, null, 2), 'utf8');
      fs.renameSync(tempPath, statePath);
    } catch (err) {
      if (fs.existsSync(tempPath)) {
        try { fs.unlinkSync(tempPath); } catch (_) {}
      }
      throw new Error(`Atomic write failure at state-manager: ${err.message}`);
    }
  }

  /**
   * Loads and deserializes a saved session state file.
   * @param {string} statePath Fully qualified path of state JSON file
   * @returns {object} Decoded state object 
   */
  load(statePath) {
    if (!fs.existsSync(statePath)) {
      throw new Error(`Execution state location does not exist: ${statePath}`);
    }
    const rawData = fs.readFileSync(statePath, 'utf8');
    const state = JSON.parse(rawData);

    if (state.schemaVersion !== "1.1.0") {
      console.warn(`[warning] Schema version mismatch logic! Found: ${state.schemaVersion}`);
    }
    return state;
  }

  /**
   * Cleans up internal structures to match Anthropic message formatting.
   * @param {Array} messages List of history objects
   * @returns {Array} Clean messages list
   */
  sanitizeMessagesForAnthropic(messages) {
    return messages.map(msg => {
      const cleanMsg = { role: msg.role };

      if (typeof msg.content === 'string') {
        cleanMsg.content = msg.content;
      } else if (Array.isArray(msg.content)) {
        cleanMsg.content = msg.content.map(block => {
          // Keep only expected parameters for tool calls and text content.
          if (block.type === 'text') {
            return { type: 'text', text: block.text };
          }
          if (block.type === 'tool_use') {
            return {
              type: 'tool_use',
              id: block.id,
              name: block.name,
              input: block.input
            };
          }
          if (block.type === 'tool_result') {
            return {
              type: 'tool_result',
              tool_use_id: block.tool_use_id,
              content: block.content,
              is_error: !!block.is_error
            };
          }
          return block;
        });
      }
      return cleanMsg;
    });
  }
}

module.exports = StateManager;
```

