  if (options.resume && options.statePath) {
    const saved = stateManager.load(options.statePath);
    messages = saved.rawMessages;
    internalState = {
      consecutiveToolFailures: saved.runnerState.consecutiveToolFailures,
      totalUsage: saved.runnerState.runningUsage,
      undoLog: saved.runnerState.undoLog
    };
  } else {
    messages.push(buildUserMessage(options.prompt, options.stdinText));
  }

  // 3. Integrate Caching with Anthropic System Prepending in credentials.js
  // Adjust the prompt cache injection logic to distribute cache points effectively.
  function applyIntelligentCaching(systemPrompt, tools, messages) {
    // 1-2. Cache system prompt and tool definitions first.
    const cachedSystem = typeof systemPrompt === 'string'
      ? [{ type: 'text', text: systemPrompt, cache_control: { type: 'ephemeral' } }]
      : systemPrompt.map((block, i, arr) => 
          i === arr.length - 1 
            ? { ...block, cache_control: { type: 'ephemeral' } } 
            : block
        );

    // Apply cache point to the last tool schema.
    const cachedTools = tools.map((tool, i, arr) => 
      i === arr.length - 1 
        ? { ...tool, cache_control: { type: 'ephemeral' } } 
        : tool
    );

    // 3-4. Place cache checkpoints in user conversation turns (e.g., at third-to-last user block)
    // to preserve token usage across long conversation loops.
    const updatedMessages = messages.map((msg, idx, arr) => {
      if (idx === arr.length - 2 && msg.role === 'user') {
        if (Array.isArray(msg.content)) {
          const contentIdx = msg.content.length - 1;
          msg.content[contentIdx].cache_control = { type: 'ephemeral' };
        } else if (typeof msg.content === 'string') {
          msg.content = [{ type: 'text', text: msg.content, cache_control: { type: 'ephemeral' } }];
        }
      }
      return msg;
    });

    return { cachedSystem, cachedTools, updatedMessages };
  }

  // 4. Run loop iterations
  for (let step = 1; step <= maxSteps; step++) {
    // Check cycle patterns before sending a payload to the bridge.
    const activeToolRequests = extractToolUses(messages[messages.length - 1]?.content);
    if (activeToolRequests.length > 0) {
      const cycleRisk = cycleDetector.trackAndVerify(activeToolRequests);
      if (cycleRisk.repeatingDetected) {
        throw new Error(`Execution Loop Refused! Reason: ${cycleRisk.reason}`);
      }
    }

    // Apply path isolation checks when executing read/write tools.
    // Example path validation check inside write_file / edit_file tool definitions:
    const check = jail.assertPath(args.path);
    if (!check.safe) {
      return { ok: false, text: check.reason };
    }

    // Apply network sandbox isolation when invoking child bash processes
    if (toolName === 'execute_bash_command') {
      const runAuth = jail.validateCommand(args.command);
      if (!runAuth.authorized) {
        return { ok: false, text: runAuth.reason };
      }

      const spawnEnv = jail.getIsolatedEnvironment(process.env);
      // Pass safe isolated child execution environments
    }

    // Save running state before sending requests to the API.
    stateManager.save(statePath, messages, { ...options, step }, internalState);
  }
}
