### Blueprint 2: Loop Cycle & Pattern Attack Detector

Save this file as `src/runner/safety/cycle-detector.js`. This utility identifies repeating execution patterns to prevent costly infinite model tool call loops.

```javascript
'use strict';

const crypto = require('crypto');

class CycleDetector {
  /**
   * Monitors execution history for repeating tool-call patterns.
   * @param {number} maxRepetitions Maximum times a single pattern can repeat before triggering a halt
   */
  constructor(maxRepetitions = 3) {
    this.maxRepetitions = maxRepetitions;
    this.executionSignatures = [];
  }

  /**
   * Records a tool turn to monitor for repeating trends.
   * @param {Array<object>} toolUses List of tool calls from a model's response turn
   * @returns {object} Repetition status reporting evaluation values
   */
  trackAndVerify(toolUses) {
    if (!toolUses || toolUses.length === 0) {
      return { repeatingDetected: false };
    }

    // Generate a unique fingerprint of the current tool calls and arguments.
    const signature = this.generateTurnFingerprint(toolUses);
    this.executionSignatures.push({
      timestamp: Date.now(),
      signature,
      tools: toolUses.map(u => ({ name: u.name, input: u.input }))
    });

    return this.detectPatterns();
  }

  /**
   * Matches sequence blocks to catch direct loop cycles (e.g., repeating Tool A, or alternating Tool A -> B -> A).
   * @returns {object} Status showing details of any detected loops
   */
  detectPatterns() {
    const list = this.executionSignatures.map(item => item.signature);
    const len = list.length;

    if (len < 2) return { repeatingDetected: false };

    // 1. Direct Repetition Check (e.g., running the exact same command over and over)
    const lastSig = list[len - 1];
    let repeatedOccurrences = 1;
    for (let i = len - 2; i >= 0; i--) {
      if (list[i] === lastSig) {
        repeatedOccurrences++;
      } else {
        break; // Stop counting when the repeating sequence is broken.
      }
    }
    if (repeatedOccurrences >= this.maxRepetitions) {
      return {
        repeatingDetected: true,
        reason: `Direct tool repetition limit reached (${repeatedOccurrences} identical tool runs).`,
        details: this.executionSignatures[len - 1].tools
      };
    }

    // 2. Multi-Turn Pattern Sequence Check (cycles of sizes from 2 to 4 steps)
    for (let patternSize = 2; patternSize <= 4; patternSize++) {
      if (len < patternSize * this.maxRepetitions) continue;

      const windowLength = patternSize * this.maxRepetitions;
      const recentWindow = list.slice(len - windowLength);

      let isAcyclic = false;
      for (let segmentIndex = 1; segmentIndex < this.maxRepetitions; segmentIndex++) {
        const baseSegment = recentWindow.slice(0, patternSize);
        const nextSegment = recentWindow.slice(segmentIndex * patternSize, (segmentIndex + 1) * patternSize);

        if (baseSegment.join(',') !== nextSegment.join(',')) {
          isAcyclic = true;
          break;
        }
      }

      if (!isAcyclic) {
        return {
          repeatingDetected: true,
          reason: `Loop pattern of size ${patternSize} detected, repeating ${this.maxRepetitions} times consecutively.`,
          details: this.executionSignatures.slice(len - patternSize).map(x => x.tools)
        };
      }
    }

    return { repeatingDetected: false };
  }

  /**
   * Generates a hash representing a step's tools and input parameters.
   */
  generateTurnFingerprint(toolUses) {
    const elements = toolUses.map(tool => {
      const normalizedArguments = this.sortObjectKeys(tool.input || {});
      return `${tool.name}:${JSON.stringify(normalizedArguments)}`;
    });
    // Double join sorting keeps elements deterministic
    const rawString = elements.sort().join('||');
    return crypto.createHash('sha256').update(rawString).digest('hex');
  }

  /**
   * Sorts object keys to ensure identical parameters generate matching hashes.
   */
  sortObjectKeys(obj) {
    if (typeof obj !== 'object' || obj === null) return obj;
    if (Array.isArray(obj)) return obj.map(item => this.sortObjectKeys(item));

    return Object.keys(obj).sort().reduce((acc, key) => {
      acc[key] = this.sortObjectKeys(obj[key]);
      return acc;
    }, {});
  }
}

module.exports = CycleDetector;
```

