### Blueprint 3: Strict Jail/Directory Whitelisting Guard

Save this file as `src/runner/safety/jail.js`. This module validates and confines all file and process execution paths inside your allowed directories, and intercepts unauthorized shell commands.

```javascript
'use strict';

const fs = require('fs');
const path = require('path');

class FileJail {
  /**
   * Initializes a write-authorized sandbox environment around a targeted CWD.
   * @param {string} allowedCwd Path to the authorized working directory
   */
  constructor(allowedCwd) {
    // Resolve symlinks to register the absolute real path
    this.authorizedRoot = fs.realpathSync(path.resolve(allowedCwd));
  }

  /**
   * Verifies if a file access path is safely confined inside the authorized folder.
   * Resolves symlinks to prevent path traversal escapes.
   * @param {string} rawTarget Relative or absolute workspace destination path
   * @returns {object} Status indicating if path is safe to access, and the resolved absolute path
   */
  assertPath(rawTarget) {
    try {
      const absolutePath = path.resolve(this.authorizedRoot, rawTarget);

      // If target exists, verify its real source resolved path to prevent symlink traversal attacks.
      let realPathToAssess = absolutePath;
      if (fs.existsSync(absolutePath)) {
        realPathToAssess = fs.realpathSync(absolutePath);
      } else {
        // If the path does not exist, verify that its parent directory is valid.
        const parentDirectory = path.dirname(absolutePath);
        if (fs.existsSync(parentDirectory)) {
          realPathToAssess = path.join(fs.realpathSync(parentDirectory), path.basename(absolutePath));
        }
      }

      const relativeRelation = path.relative(this.authorizedRoot, realPathToAssess);
      const escapesSandbox = relativeRelation.startsWith('..') || path.isAbsolute(relativeRelation);

      if (escapesSandbox) {
        return {
          safe: false,
          reason: `Access refused: Target path '${realPathToAssess}' escapes the sandbox at '${this.authorizedRoot}'.`,
          resolvedPath: null
        };
      }

      return {
        safe: true,
        resolvedPath: realPathToAssess
      };
    } catch (err) {
      return {
        safe: false,
        reason: `Fatal security checks error analyzing target: ${err.message}`,
        resolvedPath: null
      };
    }
  }

  /**
   * Validates shell arguments against a strict denylist when execution privileges are active.
   * @param {string} commandRaw Raw input string containing complete execution commands
   * @returns {object} Status showing command authorization decisions
   */
  validateCommand(commandRaw) {
    const dangerousPatterns = [
      /rm\s+-rf\s+(~|\/|\*|\$|\w+)/i,              // Malicious broad deletions
      /curl\s+.*\s*\|\s*(bash|sh|node)/i,          // Piping downloaded scripts directly into shells
      /wget\s+.*\s*\|\s*(bash|sh|node)/i,
      />\s*\/dev\/null/i,                           // Silencing execution routes to hide process outputs
      /chmod\s+.*777/i,                             // Direct high permissions changes
      /(\/etc\/passwd|\/etc\/shadow|\.ssh\/id_rsa)/i // Accessing protected operating system paths
    ];

    for (const pattern of dangerousPatterns) {
      if (pattern.test(commandRaw)) {
        return {
          authorized: false,
          reason: `Command execution blocked: Matches dangerous structural expression pattern: ${pattern.toString()}`
        };
      }
    }

    return { authorized: true };
  }

  /**
   * Prepares environment overrides to safely isolate system calls when network access is disabled.
   * @param {object} baseEnv Original system environment configurations
   * @returns {object} Environment overrides with broken loopback proxy definitions
   */
  getIsolatedEnvironment(baseEnv = process.env) {
    return {
      ...baseEnv,
      // Routes TCP/UDP connections to an unused local address to block network access.
      http_proxy: 'http://127.0.0.1:9999',
      https_proxy: 'http://127.0.0.1:9999',
      all_proxy: 'socks5://127.0.0.1:9999',
      HTTP_PROXY: 'http://127.0.0.1:9999',
      HTTPS_PROXY: 'http://127.0.0.1:9999',
      ALL_PROXY: 'socks5://127.0.0.1:9999',
      // Block common node processes from fetching network files
      NODE_EXTRA_CA_CERTS: '',
      NODE_TLS_REJECT_UNAUTHORIZED: '1'
    };
  }
}

module.exports = FileJail;
```

