             if [[ ! "$(realpath "$real_target")" =~ ^"$WORKSPACE_DIR" ]]; then
                rm -v "$symlink_file"
             fi
         done
     fi
  else
     echo -e "${GREEN}[AUDIT]${NC} No out-of-boundary symlink vulnerabilities found."
  fi
}

