## A Beginner-Safe Launcher: `run-agent.sh`

Save this in your project root. It runs a workspace backup, scans for symlink escapes, checks the bridge port, and launches the runner with conservative limits. ⚠️ The `chmod` and `tar` lines write to your disk; review them before running.

```bash
#!/usr/bin/env bash
# run-agent.sh — Hardened launcher for the local bridge runner.
set -euo pipefail

RED='\033[0;31m'; GRN='\033[0;32m'; YLW='\033[0;33m'; BLU='\033[0;34m'; NC='\033[0m'
BRIDGE_PORT="${BRIDGE_PORT:-11436}"
RUNNER_HOME="${HOME}/.bridge-runner"
LOG_DIR="${RUNNER_HOME}/logs"
BACKUP_DIR="${RUNNER_HOME}/backups"
WORKSPACE_DIR="$(pwd)"
mkdir -p "$LOG_DIR" "$BACKUP_DIR"

backup_workspace() {
  local ts; ts=$(date +%Y%m%d_%H%M%S)
  local out="$BACKUP_DIR/workspace_${ts}.tar.gz"
  echo -e "${YLW}[backup]${NC} $out"
  tar --exclude='./node_modules' --exclude='./.git' --exclude='./.bridge-runner' \
      -czf "$out" .
}

audit_symlinks() {
  echo -e "${YLW}[audit]${NC} scanning for out-of-workspace symlinks…"
  local bad=0
  while IFS= read -r link; do
    local resolved
    resolved="$(readlink -f "$link" 2>/dev/null || true)"
    if [[ -z "$resolved" || "$resolved" != "$WORKSPACE_DIR"* ]]; then
      echo -e "  ${RED}[escape]${NC} $link -> $resolved"
      bad=$((bad+1))
    fi
  done < <(find . -type l 2>/dev/null)
  if (( bad > 0 )); then
    read -r -p "Delete the $bad escaping symlink(s)? (y/N) " ans
    [[ "$ans" =~ ^[Yy]$ ]] && find . -type l -exec sh -c '
      r="$(readlink -f "$1" 2>/dev/null || echo /dev/null)"
      [ "${r#'"$WORKSPACE_DIR"'}" = "$r" ] && rm -v -- "$1"
    ' _ {} \;
  else
    echo -e "  ${GRN}[ok]${NC} no escapes."
  fi
}

[[ $# -lt 1 ]] && { echo "usage: $0 \"<task prompt>\""; exit 1; }

backup_workspace
audit_symlinks

if ! lsof -i ":${BRIDGE_PORT}" >/dev/null 2>&1; then
  echo -e "${RED}[error]${NC} bridge not listening on $BRIDGE_PORT — start the VS Code extension first."
  exit 1
fi

echo -e "${BLU}[run]${NC} launching with conservative limits…"
node bin/local-bridge-runner.js \
  --cwd "$WORKSPACE_DIR" \
  --max-steps 10 \
  --shell-timeout 15000 \
  --output-format text \
  "$1"
```

```bash
chmod +x run-agent.sh
./run-agent.sh "Scan the project and list files larger than 10KB"
```

